#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int cutRod(vector<int>& prices) {
        int n = prices.size();
        vector<int> dp(n + 1, 0);
        for (int i = 1; i <= n; i++) {
            int max_val = 0;
            for (int j = 1; j <= i; j++) {
                max_val = max(max_val, prices[j - 1] + dp[i - j]);
            }
            dp[i] = max_val;
        }
        return dp[n];
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> prices(n);
    for (int i = 0; i < n; i++) cin >> prices[i];
    Solution sol;
    int ans = sol.cutRod(prices);
    cout << ans << "\n";
    return 0;
}
